import os
import subprocess
from google.cloud import storage
from flask import escape

def image_conversion(event, context):
    # Validate event data
    if 'name' not in event or 'bucket' not in event:
        raise ValueError("Invalid event data")

    bucket_name = escape(event['bucket'])
    file_name = escape(event['name'])
    
    # Define allowed file types and conversion options
    allowed_file_types = ['.jpg', '.jpeg', '.png', '.gif']
    conversion_options = ['-resize', '-quality']

    # Extract file extension and validate
    file_extension = os.path.splitext(file_name)[1].lower()
    if file_extension not in allowed_file_types:
        raise ValueError("File type not allowed")

    # Define input and output paths
    input_blob = f"gs://{bucket_name}/{file_name}"
    output_blob = f"gs://{bucket_name}/converted/{file_name}"

    # Prepare the convert command
    command = ['convert', input_blob, *conversion_options, '100', output_blob]

    # Execute the command securely
    try:
        subprocess.call(command)
    except Exception as e:
        raise RuntimeError(f"Image conversion failed: {str(e)}")